import subprocess
import ipaddress

# Automated segmentation validation — runs from out-of-scope test host
BLOCKED_SUBNETS = [
    "10.10.5.0/24",   # CDE subnet (vector DB, model artefact store)
    "10.10.6.0/24",   # Training cluster subnet
]
ALLOWED_EGRESS = {
    "api.openai.com",
    "api.anthropic.com",
}

def test_cde_not_reachable_from_oos(test_host_ip: str) -> dict:
    results = {}
    for subnet in BLOCKED_SUBNETS:
        net = ipaddress.ip_network(subnet)
        # Sample a host address (not broadcast)
        target = str(list(net.hosts())[0])
        proc = subprocess.run(
            ["nc", "-z", "-w", "3", target, "443"],
            capture_output=True,
        )
        reachable = proc.returncode == 0
        results[subnet] = {
            "reachable": reachable,
            "pass": not reachable,   # must be NOT reachable
        }
    return results
